    private static void addUpgradedDeckCard(State s, String id) {
        Card c = new Card(id);
        c.upgraded = true;
        s.deck.add(c);
    }

    private static int buildCoreFocus(String id) {
        if ("t_core_overload".equals(id)) return BUILD_OVERLOAD;
        if ("t_core_echo".equals(id)) return BUILD_ECHO;
        if ("t_core_brew".equals(id)) return BUILD_BREW;
        if ("t_core_gold".equals(id)) return BUILD_GOLD;
        if ("t_core_blood".equals(id)) return BUILD_BLOOD;
        if ("t_core_forge".equals(id)) return BUILD_FORGE;
        if ("t_core_status".equals(id)) return BUILD_STATUS;
        if ("t_core_cycle".equals(id)) return BUILD_CYCLE;
        if ("t_core_guard".equals(id)) return BUILD_GUARD;
        return -1;
    }

    private static boolean isBuildCoreTalent(String id) {
        return buildCoreFocus(id) >= 0;
    }

    private static boolean hasBuildCoreTalent(State s) {
        if (s == null || s.talents == null) {
            return false;
        }
        for (String id : s.talents) {
            if (isBuildCoreTalent(id)) {
                return true;
            }
        }
        return false;
    }

    private static int activeBuildCoreFocus(State s) {
        if (s == null || s.talents == null) {
            return -1;
        }
        int bestFocus = -1;
        int bestScore = -9999;
        for (String id : s.talents) {
            int focus = buildCoreFocus(id);
            if (focus < 0) {
                continue;
            }
            int score = buildScoutFocusScore(s, focus) + buildFocusDeckCards(s, focus) * 4;
            if (score > bestScore) {
                bestScore = score;
                bestFocus = focus;
            }
        }
        return bestFocus;
    }

    private static int buildCoreTier(State s, int focus) {
        int score = buildScoutFocusScore(s, focus);
        if (score >= 80) return 3;
        if (score >= 55) return 2;
        return 1;
    }

    private static void applyBuildCorePickup(State s, int focus) {
        CardDef reward = buildCoreRewardCard(focus);
        if (reward != null) {
            addUpgradedDeckCard(s, reward.id);
        }
        s.masterySkillCharge = Math.max(s.masterySkillCharge, 2);
        if (focus == BUILD_OVERLOAD) {
            s.masterySkillCharge = Math.max(s.masterySkillCharge, 3);
        } else if (focus == BUILD_ECHO) {
            addUpgradedDeckCard(s, "hybrid_echo_step");
            s.masterySkillCharge = Math.max(s.masterySkillCharge, 2);
        } else if (focus == BUILD_BREW) {
            while (s.potions.size() < Math.min(potionLimit(s), 2)) {
                s.potions.add(POTION_LIBRARY.get(s.run.nextInt(POTION_LIBRARY.size())).id);
            }
        } else if (focus == BUILD_GOLD) {
            s.gold += 90;
        } else if (focus == BUILD_BLOOD) {
            s.maxHp += 7;
            s.hp += 7;
        } else if (focus == BUILD_FORGE) {
            upgradeRandomDeckCard(s);
            upgradeRandomDeckCard(s);
        } else if (focus == BUILD_STATUS) {
            removeStatusCard(s);
            s.maxHp += 3;
            s.hp += 3;
        } else if (focus == BUILD_CYCLE) {
            addUpgradedDeckCard(s, "confluence_chord");
        } else if (focus == BUILD_GUARD) {
            s.maxHp += 6;
            s.hp += 6;
        }
        log(s, "构筑核心锚定：" + BUILD_FOCUS_NAMES[focus] + "。");
    }

    private static int buildCoreCardBonus(State s, CardDef d) {
        int focus = activeBuildCoreFocus(s);
        if (focus < 0 || d == null) {
            return 0;
        }
        int value = buildFocusCardValue(d, focus);
        if (value <= 0) {
            return 0;
        }
        int bonus = 2 + Math.min(16, value / 2) + buildCoreTier(s, focus) * 2;
        if (value >= 8) {
            bonus += 6;
        }
        if (d.rarity == 2) {
            bonus += 2;
        }
        return bonus;
    }

    private static int buildCoreRelicBonus(State s, String id) {
        int focus = activeBuildCoreFocus(s);
        if (focus < 0 || id == null) {
            return 0;
        }
        int value = relicFocusValue(id, focus);
        return value <= 0 ? 0 : value * 3 + buildCoreTier(s, focus);
    }

    private static void triggerBuildCoreAfterPlay(State s, Card c, CardDef d) {
        int focus = activeBuildCoreFocus(s);
        if (focus < 0 || c == null || d == null) {
            return;
        }
        int value = buildFocusCardValue(d, focus);
        if (value < 8) {
            return;
        }
        int tier = buildCoreTier(s, focus);
        int limit = 1 + tier;
        if (s.buildCoreTriggersThisTurn >= limit) {
            return;
        }
        s.buildCoreTriggersThisTurn++;
        addProfessionSkillCharge(s, 1);
        if (focus == BUILD_OVERLOAD) {
            Enemy e = firstLiving(s);
            if (e != null) {
                e.mark += 1;
                damageEnemy(s, e, 3 + s.act * 2 + Math.min(12, value / 2 + s.professionSkillCharge / 2), true);
            }
            if (s.professionSkillCharge >= PROF_SKILL_MAX && s.buildCoreTriggersThisTurn == limit) {
                gainBlock(s, 2 + s.act + tier);
            }
        } else if (focus == BUILD_ECHO) {
            s.voidEngine++;
            if (s.buildCoreTriggersThisTurn == 1 || (tier >= 3 && s.cardsPlayedThisTurn >= 3)) {
                Card echo = new Card(d.createEcho || c.temp ? "quick_cut" : "void_echo");
                echo.temp = true;
                addToHand(s, echo);
            }
            if (tier >= 2 && (c.temp || d.createEcho)) {
                draw(s, 1);
            }
        } else if (focus == BUILD_BREW) {
            Enemy e = firstLiving(s);
            if (e != null) {
                e.burn += 1 + tier + s.burnPower / 2;
                e.bind += 1 + s.bindPower / 2;
                if (d.createPotion || d.spreadStatus) {
                    e.vulnerable += 1;
                }
            }
            if (d.createPotion && s.potions.size() < potionLimit(s) && s.buildCoreTriggersThisTurn == 1) {
                s.potions.add(POTION_LIBRARY.get(s.run.nextInt(POTION_LIBRARY.size())).id);
            }
        } else if (focus == BUILD_GOLD) {
            int income = 2 + tier + Math.min(6, value / 5);
            s.gold += income;
            gainBlock(s, 2 + tier + Math.min(7, s.gold / 100));
            if ((d.goldGain > 0 || d.goldDamage || d.goldBlock) && s.buildCoreTriggersThisTurn == limit) {
                draw(s, 1);
            }
        } else if (focus == BUILD_BLOOD) {
            if (s.hp > 1 && (d.hpLoss > 0 || d.createWound || "wound".equals(c.id))) {
                gainBlock(s, 3 + tier + Math.min(8, Math.max(0, s.maxHp - s.hp) / 6));
            } else {
                s.hp = Math.min(s.maxHp, s.hp + 1 + tier / 2);
            }
            Enemy e = firstLiving(s);
            if (e != null && (s.hp <= s.maxHp * 2 / 3 || d.createWound || "wound".equals(c.id))) {
                e.vulnerable += 1;
                damageEnemy(s, e, 3 + s.act + Math.min(12, Math.max(0, s.maxHp - s.hp) / 5), true);
            }
        } else if (focus == BUILD_FORGE) {
            gainBlock(s, 2 + s.act + tier);
            if (d.upgradeRandom || c.upgraded || s.buildCoreTriggersThisTurn == limit) {
                upgradeRandomHandCard(s);
            }
            if (tier >= 3 && (d.scry > 0 || d.upgradeRandom)) {
                draw(s, 1);
            }
        } else if (focus == BUILD_STATUS) {
            Enemy e = firstLiving(s);
            if (e != null) {
                e.mark += 1;
                e.vulnerable += 1;
                e.bind += 1 + s.bindPower / 2;
                damageEnemy(s, e, 3 + s.act * 2 + Math.min(14, bestEnemyPressure(s) / 3 + value / 3), true);
            }
            if (tier >= 2 && (d.burn > 0 || d.bind > 0 || d.vulnerable > 0)) {
                gainBlock(s, 2 + s.act);
            }
        } else if (focus == BUILD_CYCLE) {
            if (s.buildCoreTriggersThisTurn == 1 || s.cardsPlayedThisTurn >= 4) {
                draw(s, 1);
            }
            if (tier >= 2 && (d.cost == 0 || d.energyGain > 0 || s.cardsPlayedThisTurn >= 4)) {
                s.energy++;
            }
        } else if (focus == BUILD_GUARD) {
            gainBlock(s, 4 + s.act + tier + Math.min(8, Math.max(d.block, s.block / 6)));
            Enemy e = firstLiving(s);
            if (e != null && (d.type == 1 || s.block >= 18)) {
                damageEnemy(s, e, 3 + s.act * 2 + Math.min(12, s.block / 8), true);
            }
        }
        if (s.buildCoreTriggersThisTurn == 1) {
            log(s, "核心响应：" + BUILD_FOCUS_NAMES[focus] + "。");
        }
    }

    private static void triggerCoreFusionAfterPlay(State s, Card c, CardDef d) {
        SkillSpecDef spec = skillSpec(s.skillSpec);
        int focus = activeBuildCoreFocus(s);
        if (spec == null || focus < 0 || c == null || d == null) {
            return;
        }
        int specValue = skillSpecCardBonus(s, d);
        int coreValue = buildFocusCardValue(d, focus);
        if (specValue < 4 || coreValue < 6) {
            return;
        }
        int level = Math.max(1, s.skillSpecLevel);
        int tier = buildCoreTier(s, focus);
        int limit = coreFusionTriggerLimit(s, level, tier);
        if (s.coreFusionTriggersThisTurn >= limit) {
            return;
        }
        s.coreFusionTriggersThisTurn++;
        int pulse = 1 + level + tier + Math.min(3, specValue / 5 + coreValue / 8);
        applyCoreFusionCardSpecPulse(s, spec.id, pulse, d);
        applyCoreFusionCardFocusPulse(s, focus, pulse, d);
        addProfessionSkillCharge(s, 1 + (pulse >= 7 ? 1 : 0));
        if (s.coreFusionTriggersThisTurn == 1) {
            log(s, "融合牌响应：" + spec.name + " / " + BUILD_FOCUS_NAMES[focus] + "。");
        }
    }

    private static void applyCoreFusionCardSpecPulse(State s, String specId, int pulse, CardDef d) {
        Enemy target = firstLiving(s);
        if ("spec_burst".equals(specId)) {
            if (target != null) {
                target.mark += 1;
                damageEnemy(s, target, 2 + s.act + Math.min(14, pulse * 2 + s.cardsPlayedThisTurn), true);
            }
        } else if ("spec_tempo".equals(specId)) {
            if (s.cardsPlayedThisTurn >= 3 || pulse >= 6) {
                draw(s, 1);
            }
            if (pulse >= 7) {
                s.energy++;
            }
        } else if ("spec_sustain".equals(specId)) {
            gainBlock(s, 2 + s.act + pulse * 2);
            if (s.hp < s.maxHp && pulse >= 5) {
                s.hp = Math.min(s.maxHp, s.hp + 1 + pulse / 3);
            }
        } else if ("spec_bulwark".equals(specId)) {
            gainBlock(s, 3 + s.act + pulse * 2 + Math.min(8, s.block / 8));
            if (target != null && (d.type == 1 || s.block >= 18)) {
                target.bind += 1 + s.bindPower / 2;
                damageEnemy(s, target, 2 + s.act + Math.min(16, s.block / 7 + pulse), true);
            }
        } else if ("spec_resonance".equals(specId)) {
            addProfessionSkillCharge(s, 1 + Math.min(2, pulse / 3));
            if ((d.createEcho || d.draw > 0 || d.energyGain > 0) && pulse >= 6) {
                draw(s, 1);
            }
        } else if ("spec_mastery".equals(specId)) {
            if (pulse >= 6) {
                CardDef reward = randomOverloadCard(s, false);
                if (reward != null) {
                    Card c = new Card(reward.id);
                    c.temp = true;
                    c.upgraded = pulse >= 8;
                    addToHand(s, c);
                }
            } else {
                addProfessionSkillCharge(s, 1);
            }
        } else if ("spec_control".equals(specId)) {
            for (Enemy e : livingEnemies(s)) {
                e.bind += 1 + s.bindPower / 2;
                e.vulnerable += pulse >= 6 ? 1 : 0;
            }
            gainBlock(s, 2 + s.act + Math.min(8, bestEnemyPressure(s) / 4 + pulse));
        } else if ("spec_assembly".equals(specId)) {
            upgradeRandomHandCard(s);
            gainBlock(s, 2 + s.act + pulse);
        } else if ("spec_echoflow".equals(specId)) {
            s.voidEngine++;
            if (pulse >= 5) {
                Card echo = new Card(d.createEcho ? "quick_cut" : "void_echo");
                echo.temp = true;
                echo.upgraded = pulse >= 7;
                addToHand(s, echo);
            }
        } else if ("spec_markchain".equals(specId)) {
            if (target != null) {
                target.mark += 1 + pulse / 5;
                if (target.mark >= 4 || pulse >= 6) {
                    damageEnemy(s, target, 2 + s.act + Math.min(16, target.mark * 2 + pulse), true);
                }
            }
        } else if ("spec_pressure".equals(specId)) {
            int pressure = bestEnemyPressure(s);
            if (target != null) {
                target.bind += 1 + s.bindPower / 2;
                damageEnemy(s, target, 2 + s.act + Math.min(14, pressure / 3 + pulse), true);
            }
            if (pressure >= 9 || pulse >= 7) {
                draw(s, 1);
            }
        } else if ("spec_salvage".equals(specId)) {
            int statuses = statusDeckCards(s) + statusHandCards(s);
            gainBlock(s, 2 + s.act + Math.min(10, s.discard.size() / 3 + statuses * 3 + pulse));
            s.gold += 2 + s.act + Math.min(8, statuses * 2 + s.discard.size() / 6 + s.exhaust.size() / 3);
            if (statuses > 0 && pulse >= 6) {
                removeStatusCard(s);
            }
        }
    }

    private static void applyCoreFusionCardFocusPulse(State s, int focus, int pulse, CardDef d) {
        Enemy target = firstLiving(s);
        if (focus == BUILD_OVERLOAD) {
            addProfessionSkillCharge(s, 1 + Math.min(2, pulse / 4));
            if (target != null) {
                target.mark += 1;
                damageEnemy(s, target, 2 + s.act + Math.min(14, pulse * 2 + s.professionSkillCharge / 3), true);
            }
        } else if (focus == BUILD_ECHO) {
            s.voidEngine++;
            if (d.createEcho || pulse >= 6) {
                Card echo = new Card("quick_cut");
                echo.temp = true;
                echo.upgraded = pulse >= 7;
                addToHand(s, echo);
            }
        } else if (focus == BUILD_BREW) {
            if (target != null) {
                target.burn += 1 + pulse / 3 + s.burnPower / 2;
                target.bind += 1 + s.bindPower / 2;
            }
            if (d.createPotion && s.potions.size() < potionLimit(s) && pulse >= 7) {
                s.potions.add(POTION_LIBRARY.get(s.run.nextInt(POTION_LIBRARY.size())).id);
            }
        } else if (focus == BUILD_GOLD) {
            int income = 3 + s.act + Math.min(10, pulse * 2 + d.goldGain / 4);
            s.gold += income;
            gainBlock(s, 2 + s.act + Math.min(8, income / 2 + s.gold / 120));
        } else if (focus == BUILD_BLOOD) {
            int missing = Math.max(0, s.maxHp - s.hp);
            if (s.hp < s.maxHp) {
                s.hp = Math.min(s.maxHp, s.hp + 1 + pulse / 3);
            }
            if (target != null) {
                target.vulnerable += 1;
                damageEnemy(s, target, 2 + s.act + Math.min(16, missing / 4 + pulse * 2), true);
            }
        } else if (focus == BUILD_FORGE) {
            upgradeRandomHandCard(s);
            gainBlock(s, 2 + s.act + pulse);
        } else if (focus == BUILD_STATUS) {
            if (target != null) {
                target.vulnerable += 1;
                target.bind += 1 + s.bindPower / 2;
                target.mark += 1;
                damageEnemy(s, target, 2 + s.act + Math.min(16, bestEnemyPressure(s) / 4 + pulse * 2), true);
            }
        } else if (focus == BUILD_CYCLE) {
            if (s.cardsPlayedThisTurn >= 3 || pulse >= 6) {
                draw(s, 1);
            }
            if (d.cost == 0 || d.energyGain > 0 || pulse >= 7) {
                s.energy++;
            }
        } else if (focus == BUILD_GUARD) {
            gainBlock(s, 3 + s.act + pulse * 2 + Math.min(8, s.block / 8));
            if (target != null && (d.type == 1 || s.block >= 18)) {
                damageEnemy(s, target, 2 + s.act + Math.min(14, s.block / 8 + pulse), true);
            }
        }
    }

    private static boolean coreFusionCardReady(State s, CardDef d) {
        if (s == null || d == null || skillSpec(s.skillSpec) == null) {
            return false;
        }
        int focus = activeBuildCoreFocus(s);
        if (focus < 0) {
            return false;
        }
        return skillSpecCardBonus(s, d) >= 4 && buildFocusCardValue(d, focus) >= 6;
    }

    private static int coreFusionTriggerLimit(State s, int level, int tier) {
        int limit = 1 + (level >= 2 ? 1 : 0) + (tier >= 3 ? 1 : 0);
        if (s != null && hasRelic(s, "resonance_lens") && "spec_resonance".equals(s.skillSpec)) {
            limit++;
        }
        return Math.min(4, limit);
    }

    private static boolean isAdvancedTalent(String id) {
        return isBuildCoreTalent(id) || "t_warden_vanguard".equals(id) || "t_duelist_masterstep".equals(id)
                || "t_alchemist_grandbrew".equals(id) || "t_ranger_apex".equals(id)
                || "t_arcanist_singularity".equals(id) || "t_merchant_monopoly".equals(id)
                || "t_bloodbound_hemocraft".equals(id) || "t_weaver_grandpattern".equals(id)
                || "t_summoner_overflow".equals(id) || "t_hexer_abysscurse".equals(id)
                || "t_inscriber_grandcodex".equals(id) || "t_tuner_grand".equals(id)
                || "t_adjudicator_grand".equals(id) || "t_astrologer_grand".equals(id)
                || "t_machinist_grand".equals(id) || "t_chronomancer_grand".equals(id)
                || "t_pactmaker_grand".equals(id) || "t_stormcaller_grand".equals(id)
                || "t_shadowdancer_grand".equals(id) || "t_runeblade_grand".equals(id)
                || "t_medium_grand".equals(id) || "t_tactician_grand".equals(id)
                || "t_prismist_grand".equals(id) || "t_dreamwalker_grand".equals(id)
                || "t_gardener_grand".equals(id) || "t_chef_grand".equals(id)
                || "t_bard_grand".equals(id) || "t_mirrorist_grand".equals(id)
                || "t_puppeteer_grand".equals(id) || "t_scavenger_grand".equals(id)
                || "t_lightkeeper_grand".equals(id) || "t_geomancer_grand".equals(id)
                || "t_witch_grand".equals(id);
    }

