    private static void upgradeRandomDeckCard(State s) {
        ArrayList<Card> pool = new ArrayList<>();
        for (Card c : s.deck) {
            CardDef d = card(c.id);
            if (d != null && d.type != 3 && !c.upgraded) {
                pool.add(c);
            }
        }
        if (!pool.isEmpty()) {
            pool.get(s.run.nextInt(pool.size())).upgraded = true;
        }
    }

    private static void upgradeDeckCard(State s, String id) {
        for (Card c : s.deck) {
            CardDef d = card(c.id);
            if (d != null && d.type != 3 && id.equals(c.id) && !c.upgraded) {
                c.upgraded = true;
                return;
            }
        }
        upgradeRandomDeckCard(s);
    }

    private static void upgradeRandomHandCard(State s) {
        ArrayList<Card> pool = new ArrayList<>();
        for (Card c : s.hand) {
            CardDef d = card(c.id);
            if (d != null && d.type != 3 && !c.upgraded) {
                pool.add(c);
            }
        }
        if (!pool.isEmpty()) {
            pool.get(s.run.nextInt(pool.size())).upgraded = true;
        }
    }

    private static boolean hasUpgradableDeckCard(State s) {
        for (Card c : s.deck) {
            CardDef d = card(c.id);
            if (d != null && d.type != 3 && !c.upgraded) {
                return true;
            }
        }
        return false;
    }

    private static int upgradedCardCount(State s) {
        int count = 0;
        for (Card c : s.deck) {
            CardDef d = card(c.id);
            if (d != null && d.type != 3 && c.upgraded) {
                count++;
            }
        }
        return count;
    }

    private static boolean hasRelic(State s, String id) {
        return s.relics.contains(id);
    }

    private static void addStatusCard(State s, String id) {
        Card card = new Card(id);
        if (s.mode == MODE_COMBAT) {
            s.discard.add(card);
        } else {
            s.deck.add(card);
            s.seenCards.add(id);
        }
    }

    private static ArrayList<Enemy> livingEnemies(State s) {
        ArrayList<Enemy> list = new ArrayList<>();
        for (Enemy e : s.enemies) {
            if (e.hp > 0) {
                list.add(e);
            }
        }
        return list;
    }

    private static int bestEnemyPressure(State s) {
        int best = 0;
        for (Enemy e : livingEnemies(s)) {
            best = Math.max(best, e.burn + e.bind + e.vulnerable + e.mark);
        }
        return best;
    }

    private static int judgmentPressure(State s) {
        int pressure = 0;
        pressure += Math.min(3, Math.max(0, s.pactFulfilled));
        pressure += Math.min(3, Math.max(0, s.pactConfluenceCards));
        pressure += Math.min(3, Math.max(0, s.pactStatusCards));
        pressure += Math.min(3, focusMaskCount(s.confluenceMask));
        pressure += Math.min(5, Math.max(0, s.confluenceChain));
        pressure += Math.min(3, Math.max(0, s.professionSkillCharge / 3));
        if (s.skillSpec != null && s.skillSpec.length() > 0) {
            pressure += Math.max(1, Math.min(3, s.skillSpecLevel));
        }
        return pressure;
    }

    private static int drainEnemyPressureForJudgment(State s, int cap) {
        int drained = 0;
        for (Enemy e : livingEnemies(s)) {
            if (drained >= cap) {
                break;
            }
            int take = Math.min(e.burn, cap - drained);
            e.burn -= take;
            drained += take;
            if (drained >= cap) {
                break;
            }
            take = Math.min(e.bind, cap - drained);
            e.bind -= take;
            drained += take;
            if (drained >= cap) {
                break;
            }
            take = Math.min(e.vulnerable, cap - drained);
            e.vulnerable -= take;
            drained += take;
            if (drained >= cap) {
                break;
            }
            take = Math.min(e.mark, cap - drained);
            e.mark -= take;
            drained += take;
        }
        return drained;
    }

    private static Enemy firstLiving(State s) {
        for (Enemy e : s.enemies) {
            if (e.hp > 0) {
                return e;
            }
        }
        return null;
    }

    private static boolean allEnemiesDead(State s) {
        for (Enemy e : s.enemies) {
            if (e.hp > 0) {
                return false;
            }
        }
        return true;
    }

    private static Card copyCard(Card c) {
        Card n = new Card(c.id);
        n.upgraded = c.upgraded;
        n.temp = c.temp;
        return n;
    }

    private static void log(State s, String text) {
        s.log.add(text);
        while (s.log.size() > 8) {
            s.log.remove(0);
        }
    }

